# 2-to-1 Multiplexer - Combinational Circuit
# MUX selects input A or B based on select line S
# Output Y = (A AND NOT S) OR (B AND S)

class Multiplexer2to1:
    def __init__(self):
        self.name = "2-to-1 MUX"

    def NOT(self, x):
        return not x

    def AND(self, x, y):
        return x and y

    def OR(self, x, y):
        return x or y

    def output(self, a, b, s):
        # Y = (A ∧ ¬S) ∨ (B ∧ S)
        term1 = self.AND(a, self.NOT(s))
        term2 = self.AND(b, s)
        return self.OR(term1, term2)

# Test all input combinations
mux = Multiplexer2to1()
print("2-to-1 Multiplexer Truth Table:")
print("S | A | B | Y")
print("---------")
for s in [0, 1]:
    for a in [0, 1]:
        for b in [0, 1]:
            y = mux.output(a, b, s)
            print(f"{s} | {a} | {b} | {int(y)}")
